Zig side:
```zig
export fn lex_state_sizeof() usize {
    return @sizeOf(State);
}

export fn lex_state_init(self: *State) void {
    self.init();
}
```

Swift side:
```swift
let size = lex_state_sizeof()
let ptr = UnsafeMutableRawPointer.allocate(byteCount: size, alignment: MemoryLayout<Int>.alignment)
let state = ptr.assumingMemoryBound(to: State.self)
lex_state_init(state)

// ... use state ...

ptr.deallocate()
```
